import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
import {
  assertInitializeOk,
  listenExpressOnRandomPort,
  mcpInitializePayload,
  openMcpHttpSseSession,
} from './mcp-http-sse-session.js';
import { createMeshLocalMcpApp } from './main.js';
import { MeshRuntime } from './mesh-runtime.js';
import { MeshEventFanout } from './sse-fanout.js';

vi.mock('./aeon-monitor-build.js', () => ({
  buildAeonMonitor: vi.fn(async () => ({
    ok: true,
    code: 'BUILD_OK',
    exitCode: 0,
    timedOut: false,
    stdout: 'ok',
    stderr: '',
    message: 'mock build ok',
  })),
}));

const gnosisRoot = resolve(dirname(fileURLToPath(import.meta.url)), '..', '..');

describe('mesh-local-mcp e2e (MCP HTTP+SSE)', () => {
  let close: (() => Promise<void>) | undefined;
  let ac: AbortController;

  beforeEach(() => {
    ac = new AbortController();
  });

  afterEach(async () => {
    ac.abort();
    if (close) await close();
    close = undefined;
  });

  it('handshakes, tools/list includes gnosis tools, and tool calls cover success + failure paths', async () => {
    const runtime = new MeshRuntime(gnosisRoot);
    const fanout = new MeshEventFanout();
    const { app, transports } = createMeshLocalMcpApp(runtime, fanout, '127.0.0.1');
    const listening = await listenExpressOnRandomPort(app, '127.0.0.1');
    close = async () => {
      ac.abort();
      for (const t of Object.values(transports)) {
        await t.close().catch(() => undefined);
      }
      await listening.close();
    };

    const sse = await openMcpHttpSseSession(listening.baseUrl, ac.signal);

    try {
      const init = await sse.request(1, mcpInitializePayload());
      assertInitializeOk(init);

      await sse.notify({ method: 'notifications/initialized' });

      const listed = await sse.request(2, { method: 'tools/list' });
      const tools = (listed.result as { tools?: ReadonlyArray<{ name: string }> })?.tools ?? [];
      const names = tools.map((t) => t.name).sort();
      expect(names).toContain('gnosis_mesh_get_config');
      expect(names).toContain('gnosis_aeon_monitor_probe');
      expect(names).toContain('gnosis_aeon_monitor_build');
      expect(names).toContain('gnosis_aeon_monitor_set_bin');
      expect(names).toContain('gnosis_mesh_runtime_snapshot');

      const probed = await sse.request(3, {
        method: 'tools/call',
        params: { name: 'gnosis_aeon_monitor_probe', arguments: {} },
      });
      const content = (probed.result as { content?: ReadonlyArray<{ type: string; text?: string }> })
        ?.content;
      expect(content?.[0]?.type).toBe('text');
      const text = content?.[0]?.text ?? '';
      const parsed = JSON.parse(text) as { ok?: boolean; details?: { probe?: { nativeBackendReady?: boolean } } };
      expect(typeof parsed.ok).toBe('boolean');

      const snapshot = await sse.request(4, {
        method: 'tools/call',
        params: { name: 'gnosis_mesh_runtime_snapshot', arguments: { recentEventLimit: 5 } },
      });
      const snapshotJson = JSON.parse(
        ((snapshot.result as { content?: Array<{ text?: string }> }).content?.[0]?.text ?? '{}'),
      ) as { details?: { recentEvents?: unknown[] } };
      expect(Array.isArray(snapshotJson.details?.recentEvents)).toBe(true);

      const buildRes = await sse.request(5, {
        method: 'tools/call',
        params: { name: 'gnosis_aeon_monitor_build', arguments: {} },
      });
      const buildJson = JSON.parse(
        ((buildRes.result as { content?: Array<{ text?: string }> }).content?.[0]?.text ?? '{}'),
      ) as { ok?: boolean; code?: string };
      expect(buildJson.ok).toBe(true);
      expect(buildJson.code).toBe('BUILD_OK');

      const invalidArgs = await sse.request(6, {
        method: 'tools/call',
        params: { name: 'gnosis_aeon_monitor_set_bin', arguments: { nope: true } },
      });
      const invalidResult = invalidArgs.result as {
        isError?: boolean;
        content?: Array<{ text?: string }>;
      };
      expect(invalidResult.isError).toBe(true);
      expect(invalidResult.content?.[0]?.text ?? '').toContain('Input validation error');

      const unknownTool = await sse.request(7, {
        method: 'tools/call',
        params: { name: 'definitely_not_a_tool', arguments: {} },
      });
      const unknownResult = unknownTool.result as { isError?: boolean };
      expect(unknownResult.isError).toBe(true);
    } finally {
      sse.disconnect();
    }
  }, 30_000);
});
